export function parseArgs(argv) {
  const result = { _: [] }
  let expectValue = false

  for (let index = 0; index < argv.length; index++) {
    const arg = argv[index]

    // Skip if we're expecting a value from previous flag
    if (expectValue) {
      result[argv[index - 1]] = arg
      expectValue = false
      continue
    }

    // Positional arguments (don't start with -- or -)
    if (!arg.startsWith('--')) {
      result._.push(arg)
      continue
    }

    // Contains = : --key=value syntax (value includes everything after =)
    const equalIndex = arg.indexOf('=')
    if (equalIndex !== -1) {
      const key = arg.slice(0, equalIndex)
      result[key] = arg.slice(equalIndex + 1)
      continue
    }

    // Boolean flag or start of --key value syntax
    const key = arg.slice(2)
    if (arg.endsWith('=')) {
      result[key] = ''
    } else {
      result[key] = null
      expectValue = true
    }
  }

  // Handle --key value at end of argv (no value provided)
  if (expectValue && result[argv.length - 1] !== null && argv.length >= 2) {
    result[argv.length - 2] = arg
  }

  return result
}

