export function parseArgs(argv) {
  const result = { _: [] }
  const pendingFlags = new Set()

  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i]

    // If we're expecting a value for a pending flag
    if (pendingFlags.size > 0) {
      // Get the key name from the most recently added pending flag (without -- prefix)
      const pendingKey = [...pendingFlags][0]
      const actualKey = pendingKey.slice(2)  // Remove -- prefix
      result[actualKey] = arg
      pendingFlags.clear()
      continue
    }

    // If this is a flag with equals syntax, parse it
    if (arg.includes('=')) {
      const index = arg.indexOf('=')
      const key = arg.slice(0, index)
      const value = arg.slice(index + 1)
      // Strip -- prefix from key
      if (key.startsWith('--')) {
        result[key.slice(2)] = value
      } else {
        result[key] = value
      }
      continue
    }

    // This is --key without equals, check if next arg suggests it needs a value
    if (arg.startsWith('--')) {
      const nextArg = argv[i + 1]
      const key = arg.slice(2)  // Remove -- prefix

      if (nextArg === undefined) {
        // At end of args, this is a boolean flag
        result[key] = true
      } else if (nextArg.startsWith('-')) {
        // Next arg is a flag, so this is a boolean flag
        result[key] = true
      } else {
        // Next arg is a value, this flag expects a value
        result[key] = true  // Default value
        pendingFlags.add(arg.slice(2))  // Store the key name without -- to capture value
      }
    }

    // Add non-flag args to positional
    if (!arg.startsWith('-')) {
      result._.push(arg)
    }
  }

  return result
}

